// ── Tag ──────────────────────────────────────────────────────────────

impl Tag {
    /// Returns the tag value with the leading `#` stripped.
    pub fn text(&self) -> String {
        let raw = self.syntax.text().to_string();
        // The HASH token is a direct child; skip it to get just the value text.
        let trimmed = raw.trim();
        trimmed
            .strip_prefix('#')
            .unwrap_or(trimmed)
            .trim()
            .to_string()
    }
}

